    title = (payload.get("title") or "").strip()
    body = payload.get("body") or ""
    slug = (payload.get("slug") or "").strip() or None
    status = (payload.get("status") or "draft").strip()
    tags = payload.get("tags") or []
    author_id = payload.get("author_id")

    if not title:
        return jsonify({"error": "title is required"}), 400

    author_oid = _oid(author_id) if author_id else None
    if author_id and not author_oid:
        return jsonify({"error": "invalid author_id"}), 400

    if tags and not isinstance(tags, list):
        return jsonify({"error": "tags must be a list"}), 400

    doc = {
        "title": title,
        "body": body,
        "slug": slug,
        "status": status,
        "tags": tags,
        "author_id": author_oid,
        "created_at": _now(),
        "updated_at": _now(),
        "published_at": payload.get("published_at"),
        "metadata": payload.get("metadata") if isinstance(payload.get("metadata"), dict) else {},
    }

    try:
        res = documents.insert_one(doc)
    except DuplicateKeyError:
        return jsonify({"error": "document already exists (duplicate slug)"}), 409

    created = documents.find_one({"_id": res.inserted_id})
    return jsonify(_jsonify_doc(created)), 201

