    skip = _parse_int(request.args.get("skip"), default=0, min_value=0, max_value=100000)

    filt = {}
    if status:
        filt["status"] = status
    if tag:
        filt["tags"] = tag
    if slug:
        filt["slug"] = slug
    if author_id:
        aoid = _oid(author_id)
        if not aoid:
            return jsonify({"error": "invalid author_id"}), 400
        filt["author_id"] = aoid

    if q:
        if q.startswith('"') and q.endswith('"') and len(q) >= 2:
            filt["$text"] = {"$search": q}
        else:
            filt["$text"] = {"$search": q}

    sort_field = sort
    direction = ASCENDING
    if sort.startswith("-"):
        sort_field = sort[1:]
        direction = DESCENDING
    if sort_field not in {"created_at", "updated_at", "published_at", "title"}:
        sort_field = "updated_at"
        direction = DESCENDING

    projection = None
    if q:
        projection = {"score": {"$meta": "textScore"}}
        cursor = documents.find(filt, projection=projection).sort([("score", {"$meta": "textScore"}), (sort_field, direction)]).skip(skip).limit(limit)
    else:
        cursor = documents.find(filt).sort(sort_field, direction).skip(skip).limit(limit)

    items = list(cursor)
    total = documents.count_documents(filt)
    return jsonify({"items": _jsonify_doc(items), "total": total, "limit": limit, "skip": skip}), 200

