@app.get("/analytics/documents/by_status")
def analytics_by_status():
    pipeline = [
        {"$group": {"_id": "$status", "count": {"$sum": 1}}},
        {"$sort": {"count": -1}},
    ]
    result = list(documents.aggregate(pipeline))
    for r in result:
        r["status"] = r.pop("_id")
    return jsonify({"items": _jsonify_doc(result)}), 200

