    pipeline = [
        {"$unwind": {"path": "$tags", "preserveNullAndEmptyArrays": False}},
        {"$group": {"_id": "$tags", "count": {"$sum": 1}}},
        {"$sort": {"count": -1}},
        {"$limit": limit},
    ]
    result = list(documents.aggregate(pipeline))
    for r in result:
        r["tag"] = r.pop("_id")
    return jsonify({"items": _jsonify_doc(result), "limit": limit}), 200

