@app.post("/aggregate")
def run_custom_aggregate():
    payload = request.get_json(silent=True) or {}
    collection = (payload.get("collection") or "documents").strip()
    pipeline = payload.get("pipeline")

    if collection not in {"documents", "users"}:
        return jsonify({"error": "collection must be 'documents' or 'users'"}), 400
    if not isinstance(pipeline, list):
        return jsonify({"error": "pipeline must be a list"}), 400

    coll = documents if collection == "documents" else users
    try:
        result = list(coll.aggregate(pipeline))
        return jsonify({"items": _jsonify_doc(result)}), 200
    except Exception as e:
        return jsonify({"error": "aggregation failed", "details": str(e)}), 400

